// In Archetype::swap_remove(row: usize) -> Option<(Entity, usize)>
fn swap_remove(&mut self, row: usize) -> Option<(Entity, usize)> {
if row >= self.entities.len() { return None; }
// Remove from all columns
for column in self.columns.values_mut() {
column.swap_remove(row);
}
// Remove from entity list
let last_idx = self.entities.len() - 1;
self.entities.swap_remove(row);
// Return swapped entity info for location update
if row < self.entities.len() {
Some((self.entities[row], row))  // (H, 5)
} else {
None  // Was last element, no swap
}
}
// Caller in World::migrate_entity()
if let Some((swapped_entity, new_row)) = source.swap_remove(source_row) {
self.entity_locations.update_row(swapped_entity, new_row);
}
